const { neon } = require("@neondatabase/serverless");
require("dotenv").config({ path: ".env.local" });

async function migrate() {
  const sql = neon(process.env.DATABASE_URL);

  console.log("Migration 010: Brand Playbook...\n");

  // Add brand_playbook JSONB column to sites
  // This stores the full playbook artifact generated by brand intelligence
  await sql`
    ALTER TABLE sites
    ADD COLUMN IF NOT EXISTS brand_playbook JSONB DEFAULT NULL
  `;
  console.log("  + sites.brand_playbook JSONB column");

  // Add wizard_state to track in-progress brand intelligence wizard
  await sql`
    ALTER TABLE sites
    ADD COLUMN IF NOT EXISTS brand_wizard_state JSONB DEFAULT NULL
  `;
  console.log("  + sites.brand_wizard_state JSONB column");

  // Hook bank — rated hooks for each site, used in caption/blog generation
  await sql`
    CREATE TABLE IF NOT EXISTS hook_bank (
      id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
      site_id UUID NOT NULL REFERENCES sites(id) ON DELETE CASCADE,
      text TEXT NOT NULL,
      category TEXT NOT NULL,
      rating TEXT NOT NULL DEFAULT 'liked',
      used_count INTEGER DEFAULT 0,
      last_used_at TIMESTAMPTZ,
      created_at TIMESTAMPTZ DEFAULT NOW()
    )
  `;
  console.log("  + hook_bank table");

  await sql`
    CREATE INDEX IF NOT EXISTS idx_hook_bank_site_rating
    ON hook_bank(site_id, rating)
  `;
  console.log("  + idx_hook_bank_site_rating index");

  // Content topic queue — generated from content strategy, feeds blog generator
  await sql`
    CREATE TABLE IF NOT EXISTS content_topics (
      id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
      site_id UUID NOT NULL REFERENCES sites(id) ON DELETE CASCADE,
      title TEXT NOT NULL,
      search_query TEXT,
      intent TEXT,
      priority TEXT DEFAULT 'medium',
      pillar TEXT,
      cluster TEXT,
      status TEXT DEFAULT 'queued',
      blog_post_id UUID REFERENCES blog_posts(id),
      created_at TIMESTAMPTZ DEFAULT NOW()
    )
  `;
  console.log("  + content_topics table");

  await sql`
    CREATE INDEX IF NOT EXISTS idx_content_topics_site_status
    ON content_topics(site_id, status)
  `;
  console.log("  + idx_content_topics_site_status index");

  console.log("\nMigration 010 complete.");
}

migrate().catch((err) => {
  console.error("Migration failed:", err);
  process.exit(1);
});
